    }

    int book(int startTime, int endTime) {
        updates[startTime] += 1;
        updates[endTime] -= 1;
        int max = 0, sum = 0;
        for (auto it = updates.begin(); it != updates.end(); ++it) {
            sum += it->second;
            max = max > sum ? max : sum;
        }
        return max;
    }
private:
    map<int, int> updates;
};
```

